mapper.sql:
SELECT ID, TABLE_ID, COL_KEY, COL_LABEL, COL_TYPE, STATUS, REMARK, COL_SELECT_KEY, MENU_ID, SORT_NUM, CREATE_BY, CREATE_BY_NAME, CREATE_TIME, UPDATE_BY, UPDATE_BY_NAME, UPDATE_TIME
FROM T_SETTING_AD_SEARCH
SORT_NUM = 1
and ID = #{id}
and TABLE_ID = #{tableId}
and COL_KEY = #{colKey}
and COL_LABEL = #{colLabel}
and COL_TYPE = #{colType}
and STATUS = #{status}
and REMARK = #{remark}
and COL_SELECT_KEY = #{colSelectKey}

mapper.delete:
